const item = $input.first();
if (!item || !item.json) return [];

const inputData = item.json;
let texto = "";

let bodyParsed = inputData.body;
if (typeof bodyParsed === "string") {
  try { bodyParsed = JSON.parse(bodyParsed); } catch(e) {}
}

if (typeof inputData.meeting_text === 'string') {
  texto = inputData.meeting_text;
} else if (bodyParsed && typeof bodyParsed.meeting_text === 'string') {
  texto = bodyParsed.meeting_text;
} else if (typeof inputData.body === 'string') {
  texto = inputData.body;
}

if (!texto || texto.trim().length === 0) {
  return [{ json: { error: "No texto" } }];
}

// --- LIMPIEZA AVANZADA DE FOTOS E IMÁGENES DE PERFIL ---
// 1. Borrar referencias entre corchetes: [Foto], [Imagen], [Avatar], [User], etc.
texto = texto.replace(/\[(Image|source|Foto|Imagen|Gráfico|Figura|Avatar|User|Profile|Picture)\s*:?\s*\d*\.?\d*\]/gi, '');

// 2. Borrar símbolos unicode comunes de avatar o imagen al inicio de línea
texto = texto.replace(/[\u{1F464}-\u{1F469}\u{1F4BB}\u{1F4C1}\u{1F5BC}\u{1F4F7}\u{1F4F8}]/gu, '');

const lineas = texto.split('\n');
const lineasLimpias = [];

for (const linea of lineas) {
  const lineaAux = linea.trim();
  if (!lineaAux) continue;

  // IDEA 3: Filtrar intervenciones cortas tras el posible nombre del orador
  const parts = lineaAux.split(':');
  const contentOnly = parts.length > 1 ? parts.slice(1).join(':').trim() : lineaAux;

  if (contentOnly.length > 20) {
    // IDEA 1: Colapsar espacios internos
    lineasLimpias.push(lineaAux.replace(/[ \t]+/g, ' '));
  }
}

texto = lineasLimpias.join('\n');

// --- CHUNK EXTREMO PARA ARCHIVOS GIGANTES ---
const CHUNK_SIZE = 100000; 
const OVERLAP = 5000;
const chunks = [];
let start = 0;

while (start < texto.length) {
  const end = Math.min(start + CHUNK_SIZE, texto.length);
  chunks.push(texto.substring(start, end));
  if (end >= texto.length) break;
  start = end - OVERLAP;
}

return chunks.map(c => ({ json: { chunk: c } }));

const currentRunIndex = $runIndex;
let context = "";

if (currentRunIndex > 0) {
   try {
     const allHTTP = $("HTTP Request").all();
     const lastRun = allHTTP[allHTTP.length - 1];
     if (lastRun && lastRun.json && lastRun.json.response) {
         const resp = lastRun.json.response;
         context = resp.length > 2000 ? resp.substring(resp.length - 2000) : resp;
     }
   } catch(e) {}
}

let basePrompt = `Sos un experto generador de minutas profesionales para VENG SA.

Actualizá la minuta acumulada con este fragmento:
${$json.chunk}

CONTEXTO ACUMULADO:
${context}

INSTRUCCIONES:
1. Integrá lo nuevo sin borrar lo anterior (como participantes o decisiones ya tomadas).
2. No uses números como 0: o 1: en las listas JSON.
3. Usá exactamente los campos indicados abajo.

Formato EXACTO de salida:
---MINUTA---
(tu resumen profesional aquí)

---JSON---
{
  "tipo_reunion": "",
  "participantes": [],
  "decisiones": [],
  "requerimientos": [],
  "acciones": [],
  "riesgos": [],
  "pendientes": []
}`;

const body = {
  model: "llama3.2",
  stream: false,
  options: { num_ctx: 32768, temperature: 0.1 },
  prompt: basePrompt
};

return [{ json: { chunk: $json.chunk, contexto: context, ollamaBody: body } }];

let accumulated = "";
try {
  const allHTTP = $("HTTP Request").all();
  accumulated = allHTTP[allHTTP.length - 1].json.response;
} catch(e) {
  accumulated = "Error recuperando items: " + e.message;
}

let minuta = 'Error al procesar';
let data_json = {};

if (accumulated.includes('---MINUTA---')) {
  const partes = accumulated.split('---MINUTA---');
  const contenido = partes[partes.length - 1];
  minuta = contenido.split('---JSON---')[0].trim();
}

try {
  const jsonMatch = accumulated.match(/\{[\s\S]*\}/);
  if (jsonMatch) data_json = JSON.parse(jsonMatch[0]);
} catch (e) {
  data_json = { error: "JSON incompleto o no encontrado" };
}

return [{ json: { minuta: minuta, json: data_json } }];
